+/// use fcp_core::enrollment::{NodeKeyAttestation, DeviceEnrollmentApproval};
+///
+/// // After enrollment approval, create node attestation
+/// let attestation = NodeKeyAttestation::sign(
+///     &owner_key,
+///     "tailscale-node-id",
+///     &approval,
+///     168, // validity hours
+/// )?;
+///
