+            zone_id: approval.zone_id.clone(),
+            signing_key: approval.signing_key.clone(),
+            encryption_key: approval.encryption_key.clone(),
+            issuance_key: approval.issuance_key.clone(),
+            tags,
+            issued_at: now,
+            expires_at,
