+        let signing_bytes = canonical_signing_bytes(
+            NODE_KEY_ATTESTATION_SCHEMA,
+            &serde_json::to_vec(&payload).map_err(|e| FcpError::Internal {
+                message: e.to_string(),
+            })?,
